#include <stdio.h>
#include <inttypes.h>
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int64_t N, X, Y; scanf("%" PRId64 " %" PRId64 " %" PRId64, &N, &X, &Y);
        int64_t low = 2 * N - X;
        if (low < 0) low = 0;
        int64_t high = Y / 3;
        if (high > N) high = N;
        if (low <= high) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

