#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); X = int(next(it)); Y = int(next(it))
        low = 2 * N - X
        if low < 0:
            low = 0
        high = Y // 3
        if high > N:
            high = N
        out.append('YES' if low <= high else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

